import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Medicamento {
  id: number;
  nombre: string;
  tipo: string;
  dias_retiro: number;
  stock_actual: number;
  fecha_vencimiento: string;
}

interface EventoSanitario {
  id: number;
  tipo_evento: string;
  fecha: string;
  descripcion: string;
  tratamiento: string;
  veterinario: string;
  costo: number;
}

const Health: React.FC = () => {
  const [activeTab, setActiveTab] = useState('medications');
  const [medicamentos, setMedicamentos] = useState<Medicamento[]>([]);
  const [animals, setAnimals] = useState<any[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState('medication');
  const [editingId, setEditingId] = useState<number | null>(null);

  const [medicationForm, setMedicationForm] = useState({
    nombre: '',
    tipo: 'Antibiótico',
    dias_retiro: '',
    dosis_recomendada: '',
    stock_actual: '',
    fecha_vencimiento: ''
  });

  const [eventForm, setEventForm] = useState({
    animal_id: '',
    tipo_evento: 'Enfermedad',
    fecha: new Date().toISOString().split('T')[0],
    descripcion: '',
    tratamiento: '',
    veterinario: '',
    costo: ''
  });

  const [vaccinationForm, setVaccinationForm] = useState({
    animal_id: '',
    vacuna: '',
    fecha_aplicacion: new Date().toISOString().split('T')[0],
    lote: '',
    proxima_dosis: '',
    responsable: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [medicamentosRes, animalsRes] = await Promise.all([
        api.get('/health/medications'),
        api.get('/animals?estado=activo')
      ]);

      setMedicamentos(medicamentosRes.data);
      setAnimals(animalsRes.data);
    } catch (error) {
      console.error('Error cargando datos de sanidad:', error);
    }
  };

  const handleMedicationSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const data = {
        ...medicationForm,
        dias_retiro: parseInt(medicationForm.dias_retiro) || 0,
        stock_actual: parseInt(medicationForm.stock_actual) || 0
      };

      if (editingId && formType === 'medication') {
        await api.put(`/health/medications/${editingId}`, data);
      } else {
        await api.post('/health/medications', data);
      }

      resetForms();
      loadData();
    } catch (error) {
      console.error('Error guardando medicamento:', error);
      alert('Error guardando medicamento');
    }
  };

  const resetForms = () => {
    setShowForm(false);
    setEditingId(null);
    setMedicationForm({
      nombre: '',
      tipo: 'Antibiótico',
      dias_retiro: '',
      dosis_recomendada: '',
      stock_actual: '',
      fecha_vencimiento: ''
    });
  };

  const handleEditMedication = (med: Medicamento) => {
    setMedicationForm({
      nombre: med.nombre,
      tipo: med.tipo,
      dias_retiro: med.dias_retiro.toString(),
      dosis_recomendada: med.dosis_recomendada || '',
      stock_actual: med.stock_actual.toString(),
      fecha_vencimiento: med.fecha_vencimiento || ''
    });
    setEditingId(med.id);
    setFormType('medication');
    setShowForm(true);
  };

  const handleDeleteMedication = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este medicamento?')) {
      try {
        await api.delete(`/health/medications/${id}`);
        loadData();
      } catch (error) {
        console.error('Error eliminando medicamento:', error);
        alert('Error eliminando medicamento');
      }
    }
  };

  const handleEventSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/health/events', {
        ...eventForm,
        animal_id: parseInt(eventForm.animal_id),
        costo: parseFloat(eventForm.costo) || 0
      });
      setShowForm(false);
      setEventForm({
        animal_id: '',
        tipo_evento: 'Enfermedad',
        fecha: new Date().toISOString().split('T')[0],
        descripcion: '',
        tratamiento: '',
        veterinario: '',
        costo: ''
      });
    } catch (error) {
      console.error('Error registrando evento:', error);
    }
  };

  const handleVaccinationSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/health/vaccinations', {
        ...vaccinationForm,
        animal_id: parseInt(vaccinationForm.animal_id)
      });
      setShowForm(false);
      setVaccinationForm({
        animal_id: '',
        vacuna: '',
        fecha_aplicacion: new Date().toISOString().split('T')[0],
        lote: '',
        proxima_dosis: '',
        responsable: ''
      });
    } catch (error) {
      console.error('Error registrando vacunación:', error);
    }
  };

  const openForm = (type: string) => {
    setFormType(type);
    setShowForm(true);
  };

  const tabStyle = (tab: string) => ({
    padding: '12px 24px',
    border: 'none',
    backgroundColor: activeTab === tab ? '#28a745' : '#f8f9fa',
    color: activeTab === tab ? 'white' : '#333',
    cursor: 'pointer',
    borderRadius: '4px 4px 0 0',
    marginRight: '2px'
  });

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h1>🏥 Sanidad Animal</h1>
        <div>
          <button 
            className="btn btn-success"
            onClick={() => openForm('medication')}
            style={{ marginRight: '10px' }}
          >
            Nuevo Medicamento
          </button>
          <button 
            className="btn btn-primary"
            onClick={() => openForm('event')}
            style={{ marginRight: '10px' }}
          >
            Evento Sanitario
          </button>
          <button 
            className="btn btn-warning"
            onClick={() => openForm('vaccination')}
          >
            Vacunación
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ marginBottom: '20px' }}>
        <button 
          style={tabStyle('medications')}
          onClick={() => setActiveTab('medications')}
        >
          💊 Medicamentos
        </button>
        <button 
          style={tabStyle('alerts')}
          onClick={() => setActiveTab('alerts')}
        >
          ⚠️ Alertas
        </button>
        <button 
          style={tabStyle('protocols')}
          onClick={() => setActiveTab('protocols')}
        >
          📋 Protocolos
        </button>
      </div>

      {/* Formularios */}
      {showForm && (
        <div className="card mb-3">
          {formType === 'medication' && (
            <div>
              <h3>{editingId && formType === 'medication' ? '✏️ Editar Medicamento' : '➕ Nuevo Medicamento'}</h3>
              <form onSubmit={handleMedicationSubmit}>
                <div className="grid grid-3">
                  <div className="form-group">
                    <label>Nombre:</label>
                    <input
                      type="text"
                      className="form-control"
                      value={medicationForm.nombre}
                      onChange={(e) => setMedicationForm({...medicationForm, nombre: e.target.value})}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Tipo:</label>
                    <select
                      className="form-control"
                      value={medicationForm.tipo}
                      onChange={(e) => setMedicationForm({...medicationForm, tipo: e.target.value})}
                    >
                      <option value="Antibiótico">Antibiótico</option>
                      <option value="Antiparasitario">Antiparasitario</option>
                      <option value="Vacuna">Vacuna</option>
                      <option value="Suplemento">Suplemento</option>
                      <option value="Analgésico">Analgésico</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Días de Retiro:</label>
                    <input
                      type="number"
                      className="form-control"
                      value={medicationForm.dias_retiro}
                      onChange={(e) => setMedicationForm({...medicationForm, dias_retiro: e.target.value})}
                    />
                  </div>
                  <div className="form-group">
                    <label>Dosis Recomendada:</label>
                    <input
                      type="text"
                      className="form-control"
                      value={medicationForm.dosis_recomendada}
                      onChange={(e) => setMedicationForm({...medicationForm, dosis_recomendada: e.target.value})}
                      placeholder="Ej: 1ml/10kg"
                    />
                  </div>
                  <div className="form-group">
                    <label>Stock Actual:</label>
                    <input
                      type="number"
                      className="form-control"
                      value={medicationForm.stock_actual}
                      onChange={(e) => setMedicationForm({...medicationForm, stock_actual: e.target.value})}
                    />
                  </div>
                  <div className="form-group">
                    <label>Fecha de Vencimiento:</label>
                    <input
                      type="date"
                      className="form-control"
                      value={medicationForm.fecha_vencimiento}
                      onChange={(e) => setMedicationForm({...medicationForm, fecha_vencimiento: e.target.value})}
                    />
                  </div>
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button type="submit" className="btn btn-success">
                    {editingId && formType === 'medication' ? '💾 Actualizar' : '💾 Guardar'} Medicamento
                  </button>
                  <button 
                    type="button" 
                    className="btn btn-secondary"
                    onClick={resetForms}
                  >
                    ❌ Cancelar
                  </button>
                </div>
              </form>
            </div>
          )}

          {formType === 'event' && (
            <div>
              <h3>Registrar Evento Sanitario</h3>
              <form onSubmit={handleEventSubmit}>
                <div className="grid grid-2">
                  <div className="form-group">
                    <label>Animal:</label>
                    <select
                      className="form-control"
                      value={eventForm.animal_id}
                      onChange={(e) => setEventForm({...eventForm, animal_id: e.target.value})}
                      required
                    >
                      <option value="">Seleccionar animal</option>
                      {animals.map(animal => (
                        <option key={animal.id} value={animal.id}>
                          {animal.identificador_unico} - {animal.nombre || 'Sin nombre'}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Tipo de Evento:</label>
                    <select
                      className="form-control"
                      value={eventForm.tipo_evento}
                      onChange={(e) => setEventForm({...eventForm, tipo_evento: e.target.value})}
                    >
                      <option value="Enfermedad">Enfermedad</option>
                      <option value="Tratamiento">Tratamiento</option>
                      <option value="Cirugía">Cirugía</option>
                      <option value="Revisión">Revisión</option>
                      <option value="Emergencia">Emergencia</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Fecha:</label>
                    <input
                      type="date"
                      className="form-control"
                      value={eventForm.fecha}
                      onChange={(e) => setEventForm({...eventForm, fecha: e.target.value})}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Veterinario:</label>
                    <input
                      type="text"
                      className="form-control"
                      value={eventForm.veterinario}
                      onChange={(e) => setEventForm({...eventForm, veterinario: e.target.value})}
                    />
                  </div>
                  <div className="form-group">
                    <label>Descripción:</label>
                    <textarea
                      className="form-control"
                      rows={3}
                      value={eventForm.descripcion}
                      onChange={(e) => setEventForm({...eventForm, descripcion: e.target.value})}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Tratamiento:</label>
                    <textarea
                      className="form-control"
                      rows={3}
                      value={eventForm.tratamiento}
                      onChange={(e) => setEventForm({...eventForm, tratamiento: e.target.value})}
                    />
                  </div>
                  <div className="form-group">
                    <label>Costo ($):</label>
                    <input
                      type="number"
                      step="0.01"
                      className="form-control"
                      value={eventForm.costo}
                      onChange={(e) => setEventForm({...eventForm, costo: e.target.value})}
                    />
                  </div>
                </div>
                <div>
                  <button type="submit" className="btn btn-success">Registrar Evento</button>
                  <button 
                    type="button" 
                    className="btn btn-secondary"
                    onClick={() => setShowForm(false)}
                    style={{ marginLeft: '10px' }}
                  >
                    Cancelar
                  </button>
                </div>
              </form>
            </div>
          )}
        </div>
      )}

      {/* Contenido de las tabs */}
      {activeTab === 'medications' && (
        <div className="card">
          <h3>Inventario de Medicamentos ({medicamentos.length})</h3>
          {medicamentos.length > 0 ? (
            <table className="table">
              <thead>
                <tr>
                  <th>Nombre</th>
                  <th>Tipo</th>
                  <th>Stock</th>
                  <th>Días Retiro</th>
                  <th>Vencimiento</th>
                  <th>Estado</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {medicamentos.map(med => {
                  const diasVencimiento = med.fecha_vencimiento ? 
                    Math.ceil((new Date(med.fecha_vencimiento).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24)) : null;

                  return (
                    <tr key={med.id}>
                      <td style={{ fontWeight: 'bold' }}>{med.nombre}</td>
                      <td>{med.tipo}</td>
                      <td>
                        <span style={{
                          padding: '4px 8px',
                          borderRadius: '4px',
                          backgroundColor: med.stock_actual < 10 ? '#f8d7da' : '#d4edda',
                          color: med.stock_actual < 10 ? '#721c24' : '#155724'
                        }}>
                          {med.stock_actual}
                        </span>
                      </td>
                      <td>{med.dias_retiro} días</td>
                      <td>{med.fecha_vencimiento ? new Date(med.fecha_vencimiento).toLocaleDateString() : '-'}</td>
                      <td>
                        {diasVencimiento !== null && (
                          <span style={{
                            padding: '4px 8px',
                            borderRadius: '4px',
                            fontSize: '12px',
                            backgroundColor: diasVencimiento < 30 ? '#f8d7da' : diasVencimiento < 60 ? '#fff3cd' : '#d4edda',
                            color: diasVencimiento < 30 ? '#721c24' : diasVencimiento < 60 ? '#856404' : '#155724'
                          }}>
                            {diasVencimiento < 0 ? 'Vencido' : `${diasVencimiento} días`}
                          </span>
                        )}
                      </td>
                      <td>
                        <div className="action-buttons">
                          <button 
                            className="btn btn-warning btn-sm"
                            onClick={() => handleEditMedication(med)}
                            title="Editar medicamento"
                          >
                            ✏️
                          </button>
                          <button 
                            className="btn btn-danger btn-sm"
                            onClick={() => handleDeleteMedication(med.id)}
                            title="Eliminar medicamento"
                          >
                            🗑️
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          ) : (
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>💊</div>
              <p>No hay medicamentos registrados</p>
            </div>
          )}
        </div>
      )}

      {activeTab === 'alerts' && (
        <div className="grid grid-2">
          <div className="card">
            <h3>⚠️ Medicamentos por Vencer</h3>
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              <p>Funcionalidad en desarrollo...</p>
            </div>
          </div>
          <div className="card">
            <h3>🚫 Animales en Retiro</h3>
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              <p>Funcionalidad en desarrollo...</p>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'protocols' && (
        <div className="card">
          <h3>📋 Protocolos Sanitarios</h3>
          <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
            <div style={{ fontSize: '48px', marginBottom: '15px' }}>📋</div>
            <p>Protocolos de vacunación y tratamientos en desarrollo...</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Health;
